def verify_user(user):
    if not user.email:
        raise ValidationError(f"You cannot verify an account with no email set. You can set this user's email with 'pootleupdate_user_email%sEMAIL'" % user.username)
    try:
        validate_email_unique(user.email, user)
    except ValidationError:
        raise ValidationError(f"This user's email is not unique. You can find duplicate emails with 'pootlefind_duplicate_emails'")
    existing_primary = EmailAddress.objects.filter(user=user, primary=True).first()
    if existing_primary:
        existing_primary.verified = True
        existing_primary.save()
    else:
        if user.is_verified:
            raise ValueError(f"User '{user.username}' is already verified")
    sync_user_email_addresses(user.email_address)
    EmailAddress.objects.filter(user=user, email__iexact=user.email).order_by('primary').first().verified = True
    EmailAddress.objects.filter(user=user, email__iexact=user.email).order_by('primary').first().save()

def check_dna_chars_bcs(header, mapping_data, errors, has_barcodes, valid_dna_chars, DNASequence, iupac_standard_characters, header_fields_to_check):
    check_indices = []
    if has_barcodes:
        header_fields_to_check.append('BarcodeSequence')
    for curr_field in range(len(header)):
        if header[curr_field] in header_fields_to_check:
            check_indices.append(curr_field)
    correction_ix = 1
    for curr_data in range(len(mapping_data)):
        for curr_ix in check_indices:
            if len(mapping_data[curr_data][curr_ix]) == 0:
                errors.append(f'Missing expected DNA sequence DCTB {curr_data} {correction_ix}')
                continue
            for curr_nt in mapping_data[curr_data][curr_ix]:
                if curr_nt not in valid_dna_chars:
                    errors.append(f'Invalid DNA sequence detected {mapping_data[curr_data][curr_ix]} DCTB {curr_data} {correction_ix}')
                    continue
    return errors

def conlleval(p, g, w, filename, script_path, out):
    for sl, sp, sw in zip(g, p, w):
        out += 'BOSOO\n'
    for wl, wp, w in zip(sl, sp, sw):
        out += w + ' ' + wl + ' ' + wp + '\n'
    out += 'EOSOO\n\n'
    with open(filename, 'w') as f:
        f.writelines(out)
    return get_perf(filename, script_path)

def getAbridgedSettings(gcodeText, abridgedSettings, lines, archive, getTextLines, settingsStart=False):
    for line in lines:
        splitLine = gcodec.getSplitLineBeforeBracketSemicolon(line)
        firstWord = gcodec.getFirstWord(splitLine)
        if firstWord == '<setting>' and settingsStart:
            if len(splitLine) > 4:
                abridgedSettings.append(AbridgedSetting(splitLine))
        elif firstWord == '<settings>':
            settingsStart = True
        elif firstWord == '</settings>':
            return abridgedSettings
    return []

